package com.hospital.management.util;import org.junit.jupiter.api.Test;import static org.junit.jupiter.api.Assertions.*;
class AppointmentStatusTransitionTest {@Test void validTransitions(){assertEquals("CONFIRMED",AppointmentStatusTransition.target("SCHEDULED","confirm").orElseThrow());assertEquals("COMPLETED",AppointmentStatusTransition.target("CONFIRMED","complete").orElseThrow());assertEquals("CANCELLED",AppointmentStatusTransition.target("CONFIRMED","cancel").orElseThrow());assertEquals("NO_SHOW",AppointmentStatusTransition.target("CONFIRMED","no_show").orElseThrow());}@Test void invalidTransitions(){assertTrue(AppointmentStatusTransition.target("SCHEDULED","complete").isEmpty());}@Test void terminalStatesBlocked(){assertTrue(AppointmentStatusTransition.isTerminal("COMPLETED"));assertTrue(AppointmentStatusTransition.target("CANCELLED","confirm").isEmpty());}}
